  1	import * as React from 'react';
  2	import { SessionTimeout } from '../../SessionTimeout/SessionTimeout';
  3	import { config } from '../../../config';
  4	import { isMultiCluster } from '../../../config';
  5	import { MILLISECONDS } from '../../../types/Common';
  6	import { Timer } from 'globals';
  7	import { KialiAppState, LoginSession } from '../../../store/Store';
  8	import { authenticationConfig } from '../../../config/AuthenticationConfig';
  9	import { AuthStrategy } from '../../../types/Auth';
 10	import moment from 'moment';
 11	import { KialiDispatch } from 'types/Redux';
 12	import { LoginThunkActions } from '../../../actions/LoginThunkActions';
 13	import { connect } from 'react-redux';
 14	import * as API from '../../../services/Api';
 15	import { kialiStyle } from 'styles/StyleUtils';
 16	import { namespacesPerClusterSelector } from 'store/Selectors';
 17	import {
 18	  Divider,
 19	  Dropdown,
 20	  DropdownGroup,
 21	  DropdownItem,
 22	  DropdownList,
 23	  MenuToggle,
 24	  MenuToggleElement
 25	} from '@patternfly/react-core';
 26	import { t } from 'utils/I18nUtils';
 27	
 28	type ReduxStateProps = {
 29	  clusters?: string[];
 30	  session?: LoginSession;
 31	};
 32	
 33	type ReduxDispatchProps = {
 34	  extendSession: (session: LoginSession) => void;
 35	  logout: () => void;
 36	};
 37	
 38	type UserProps = ReduxStateProps & ReduxDispatchProps;
 39	
 40	type UserState = {
 41	  checkSessionTimerId?: Timer;
 42	  isDropdownOpen: boolean;
 43	  isSessionTimeoutDismissed: boolean;
 44	  showSessionTimeOut: boolean;
 45	  timeCountDownSeconds: number;
 46	  timeLeftTimerId?: Timer;
 47	};
 48	
 49	const dropdownStyle = kialiStyle({
 50	  paddingLeft: 0,
 51	  paddingRight: 0
 52	});
 53	
 54	class UserDropdownComponent extends React.Component<UserProps, UserState> {
 55	  constructor(props: UserProps) {
 56	    super(props);
 57	
 58	    this.state = {
 59	      showSessionTimeOut: false,
 60	      timeCountDownSeconds: this.timeLeft() / MILLISECONDS,
 61	      isSessionTimeoutDismissed: false,
 62	      isDropdownOpen: false
 63	    };
 64	  }
 65	
 66	  componentDidMount(): void {
 67	    const checkSessionTimerId = setInterval(() => {
 68	      this.checkSession();
 69	    }, 3000);
 70	
 71	    const timeLeftTimerId = setInterval(() => {
 72	      this.setState({ timeCountDownSeconds: this.timeLeft() / MILLISECONDS });
 73	    }, 1000);
 74	
 75	    this.setState({
 76	      checkSessionTimerId: checkSessionTimerId,
 77	      timeLeftTimerId: timeLeftTimerId
 78	    });
 79	  }
 80	
 81	  componentWillUnmount(): void {
 82	    if (this.state.checkSessionTimerId) {
 83	      clearInterval(this.state.checkSessionTimerId);
 84	    }
 85	
 86	    if (this.state.timeLeftTimerId) {
 87	      clearInterval(this.state.timeLeftTimerId);
 88	    }
 89	  }
 90	
 91	  timeLeft = (): number => {
 92	    const expiresOn = moment(this.props.session!.expiresOn);
 93	
 94	    if (expiresOn <= moment()) {
 95	      this.props.logout();
 96	    }
 97	
 98	    return expiresOn.diff(moment());
 99	  };
100	
101	  checkSession = (): void => {
102	    if (this.timeLeft() < config.session.timeOutforWarningUser) {
103	      this.setState({ showSessionTimeOut: true });
104	    }
105	  };
106	
107	  handleLogout = (): void => {
108	    if (authenticationConfig.logoutEndpoint) {
109	      API.logout()
110	        .then(_ => {
111	          (document.getElementById('openshiftlogout') as HTMLFormElement).submit();
112	        })
113	        .catch(error => {
114	          const errorMsg = error.response && error.response.data.error ? error.response.data.error : error.message;
115	          console.error(`Logout failed. "kiali-token" cookie may need to be cleared manually: ${errorMsg}`);
116	          (document.getElementById('openshiftlogout') as HTMLFormElement).submit();
117	        });
118	    } else {
119	      this.props.logout();
120	    }
121	  };
122	
123	  extendSession = (session: LoginSession): void => {
124	    this.props.extendSession(session);
125	    this.setState({ showSessionTimeOut: false });
126	  };
127	
128	  onDropdownToggle = (isDropdownOpen: boolean): void => {
129	    this.setState({
130	      isDropdownOpen
131	    });
132	  };
133	
134	  onDropdownSelect = (): void => {
135	    this.setState({
136	      isDropdownOpen: !this.state.isDropdownOpen
137	    });
138	  };
139	
140	  render(): React.ReactNode {
141	    const { isDropdownOpen } = this.state;
142	
143	    const clusterIsInSessionInfo = (cluster: string): boolean =>
144	      this.props.session?.clusterInfo?.[cluster] !== undefined;
145	
146	    const canLogout =
147	      authenticationConfig.strategy !== AuthStrategy.anonymous && authenticationConfig.strategy !== AuthStrategy.header;
148	
149	    // We want to show a dropdown per cluster the user is not logged into yet.
150	    // The clusters you are logged into are in session.clusterInfo and all
151	    // the clusters are in authenticationConfig.authorizationEndpointPerCluster.
152	    // So the clusters you are not logged into is authenticationConfig.authorizationEndpointPerCluster - session.clusterInfo.
153	    // Two groups of clusters: those you are logged into and those you are not.
154	    let loggedInClusters: { cluster: string; endpoint: string }[] = [];
155	    let loggedOutClusters: { cluster: string; endpoint: string }[] = [];
156	    if (authenticationConfig.authorizationEndpointPerCluster !== undefined) {
157	      Object.entries(authenticationConfig.authorizationEndpointPerCluster).forEach(([cluster, endpoint]) => {
158	        clusterIsInSessionInfo(cluster)
159	          ? loggedInClusters.push({ cluster: cluster, endpoint: endpoint })
160	          : loggedOutClusters.push({ cluster: cluster, endpoint: endpoint });
161	      });
162	    }
163	
164	    return (
165	      <>
166	        <SessionTimeout
167	          onLogout={this.props.logout}
168	          onExtendSession={this.extendSession}
169	          onDismiss={this.dismissHandler}
170	          show={this.state.showSessionTimeOut && !this.state.isSessionTimeoutDismissed}
171	          timeOutCountDown={this.state.timeCountDownSeconds}
172	        />
173	
174	        {this.props.session && !canLogout && <>{this.props.session.username}</>}
175	
176	        {this.props.session && canLogout && (
177	          <Dropdown
178	            toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
179	              <MenuToggle
180	                ref={toggleRef}
181	                className={dropdownStyle}
182	                variant="plainText"
183	                onClick={() => this.onDropdownToggle(!isDropdownOpen)}
184	                isExpanded={isDropdownOpen}
185	              >
186	                {this.props.session?.username}
187	              </MenuToggle>
188	            )}
189	            isOpen={isDropdownOpen}
190	            onSelect={this.onDropdownSelect}
191	            popperProps={{ position: 'right' }}
192	            onOpenChange={(isOpen: boolean) => this.onDropdownToggle(isOpen)}
193	          >
194	            {isMultiCluster && loggedInClusters.length > 0 && (
195	              <>
196	                <DropdownGroup label="logged-in clusters" labelHeadingLevel="h3">
197	                  <DropdownList>
198	                    {loggedInClusters.map(clusterInfo => {
199	                      return (
200	                        <DropdownItem isDisabled={true} key={clusterInfo.cluster}>
201	                          {clusterInfo.cluster}
202	                        </DropdownItem>
203	                      );
204	                    })}
205	                  </DropdownList>
206	                </DropdownGroup>
207	                <Divider component="li" />
208	              </>
209	            )}
210	
211	            {isMultiCluster && loggedOutClusters.length > 0 && (
212	              <>
213	                <DropdownGroup label="logged-out clusters" labelHeadingLevel="h3">
214	                  <DropdownList>
215	                    {loggedOutClusters.map(clusterInfo => {
216	                      return (
217	                        <DropdownItem key={clusterInfo.cluster} to={clusterInfo.endpoint}>
218	                          {t('Login to {{cluster}}', { cluster: clusterInfo.cluster })}
219	                        </DropdownItem>
220	                      );
221	                    })}
222	                  </DropdownList>
223	                </DropdownGroup>
224	                <Divider component="li" />
225	              </>
226	            )}
227	
228	            <DropdownItem key={'user_logout_option'} onClick={this.handleLogout} isDisabled={!canLogout}>
229	              {t('Logout')}
230	            </DropdownItem>
231	          </Dropdown>
232	        )}
233	
234	        {authenticationConfig.strategy === AuthStrategy.openshift && authenticationConfig.logoutEndpoint && (
235	          <form id="openshiftlogout" action={authenticationConfig.logoutEndpoint} method="post">
236	            <input type="hidden" name="then" value={authenticationConfig.logoutRedirect} />
237	          </form>
238	        )}
239	      </>
240	    );
241	  }
242	
243	  private dismissHandler = (): void => {
244	    this.setState({ isSessionTimeoutDismissed: true });
245	  };
246	}
247	
248	const mapStateToProps = (state: KialiAppState): ReduxStateProps => ({
249	  clusters: Array.from(namespacesPerClusterSelector(state).keys()),
250	  session: state.authentication.session
251	});
252	
253	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => ({
254	  logout: () => dispatch(LoginThunkActions.logout()),
255	  extendSession: (session: LoginSession) => dispatch(LoginThunkActions.extendSession(session))
256	});
257	
258	export const UserDropdown = connect(mapStateToProps, mapDispatchToProps)(UserDropdownComponent);

